css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #050507; color: white; }
.navbar { display: flex; justify-content: space-between; align-items: center; padding: 24px 60px; }
.brand { font-size: 18px; font-weight: 800; letter-spacing: 0.05em; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: rgba(255,255,255,0.5); text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #34d399; }
.hero { padding: 60px 60px 50px; max-width: 760px; }
.badge { display: inline-block; color: #34d399; font-size: 12px; font-weight: 800; letter-spacing: 0.18em; margin-bottom: 24px; }
.hero h1 { font-size: 54px; font-weight: 800; line-height: 1.2; margin-bottom: 20px; }
.hero h1 span { color: #34d399; }
.hero p { color: rgba(255,255,255,0.5); font-size: 15px; line-height: 1.8; max-width: 520px; }
.gallery { padding: 30px 60px 70px; }
.filter-row { display: flex; gap: 10px; margin-bottom: 26px; flex-wrap: wrap; }
.filter { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: rgba(255,255,255,0.55); padding: 9px 18px; border-radius: 999px; font-size: 13px; font-weight: 700; cursor: pointer; }
.filter.active { background: rgba(52,211,153,0.15); color: #34d399; border-color: rgba(52,211,153,0.3); }
.grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 18px; }
.grid-item { aspect-ratio: 1; border-radius: 16px; display: flex; align-items: center; justify-content: center; font-size: 56px; cursor: pointer; transition: 0.2s; }
.grid-item:hover { transform: scale(1.03); }
.grid-item.g1 { background: linear-gradient(150deg, #1a2e2a, #050507); }
.grid-item.g2 { background: linear-gradient(150deg, #1a2438, #050507); }
.grid-item.g3 { background: linear-gradient(150deg, #2a1a38, #050507); }
.grid-item.g4 { background: linear-gradient(150deg, #2e2a1a, #050507); }
.grid-item.g5 { background: linear-gradient(150deg, #1a382e, #050507); }
.grid-item.g6 { background: linear-gradient(150deg, #38241a, #050507); }
.skills { padding: 60px; background: rgba(255,255,255,0.02); }
.skills h2 { font-size: 28px; font-weight: 800; margin-bottom: 30px; text-align: center; }
.skill-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 24px; max-width: 900px; margin: 0 auto; }
.skill { text-align: center; }
.sicon { font-size: 28px; display: block; margin-bottom: 10px; }
.skill h3 { font-size: 15px; font-weight: 700; margin-bottom: 10px; }
.bar { height: 6px; background: rgba(255,255,255,0.08); border-radius: 999px; overflow: hidden; }
.bar div { height: 100%; background: linear-gradient(90deg, #34d399, #6ee7b7); border-radius: 999px; }
.contact { text-align: center; padding: 80px 60px; }
.contact h2 { font-size: 28px; font-weight: 800; margin-bottom: 10px; }
.contact p { color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 26px; }
.contact button { background: rgba(52,211,153,0.15); color: #34d399; border: none; padding: 15px 32px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
.modal { position: fixed; inset: 0; background: rgba(0,0,0,0.85); display: none; align-items: center; justify-content: center; padding: 20px; z-index: 10; }
.modal.show { display: flex; }
.modal-content { background: #0e0e12; border-radius: 16px; padding: 28px; max-width: 420px; width: 100%; text-align: center; }
.modal-render { aspect-ratio: 1; background: linear-gradient(150deg, #1a2e2a, #050507); border-radius: 14px; display: flex; align-items: center; justify-content: center; font-size: 80px; margin-bottom: 18px; }
.modal-content h2 { font-size: 20px; font-weight: 800; margin-bottom: 4px; }
.modal-content span { display: block; color: rgba(255,255,255,0.4); font-size: 12.5px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 20px; }
.close-btn { background: rgba(52,211,153,0.15); color: #34d399; border: none; padding: 12px 28px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
@media (max-width: 900px) { .navbar, .hero, .gallery, .skills, .contact { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 32px; } }

