const items = [
  { emoji: '🧙', cat: 'character', cls: 'g1', name: 'Fantastik Karakter Tasarımı' },
  { emoji: '🏯', cat: 'environment', cls: 'g2', name: 'Mistik Tapınak Ortamı' },
  { emoji: '👟', cat: 'product', cls: 'g3', name: 'Ayakkabı Ürün Render' },
  { emoji: '🤖', cat: 'character', cls: 'g4', name: 'Robot Karakter Modeli' },
  { emoji: '🌋', cat: 'environment', cls: 'g5', name: 'Volkanik Ada Sahnesi' },
  { emoji: '⌚', cat: 'product', cls: 'g6', name: 'Akıllı Saat Render' },
  { emoji: '🐉', cat: 'character', cls: 'g1', name: 'Ejderha Konsepti' },
  { emoji: '🏙️', cat: 'environment', cls: 'g2', name: 'Cyberpunk Şehir' },
  { emoji: '🎧', cat: 'product', cls: 'g3', name: 'Kulaklık Render Serisi' }
];

function renderGrid(filter) {
  const grid = document.getElementById('grid');
  grid.innerHTML = '';
  items
    .filter(i => filter === 'all' || i.cat === filter)
    .forEach(i => {
      const div = document.createElement('div');
      div.className = `grid-item ${i.cls}`;
      div.textContent = i.emoji;
      div.addEventListener('click', () => openModal(i));
      grid.appendChild(div);
    });
}

function filterWork(btn, filter) {
  document.querySelectorAll('.filter').forEach(f => f.classList.remove('active'));
  btn.classList.add('active');
  renderGrid(filter);
}

const catLabels = { character: 'Karakter', environment: 'Ortam', product: 'Ürün Render' };

function openModal(item) {
  document.getElementById('modalRender').textContent = item.emoji;
  document.getElementById('modalTitle').textContent = item.name;
  document.getElementById('modalCat').textContent = catLabels[item.cat];
  document.getElementById('modal').classList.add('show');
}

function closeModal(e) {
  if (e.target.id === 'modal' || e.target.classList.contains('close-btn')) {
    document.getElementById('modal').classList.remove('show');
  }
}

function contactMe() {
